import React, { useState, useRef } from 'react';
import { db } from '../../utils/firebase';
import { collection, addDoc, doc, updateDoc, increment, getDoc } from 'firebase/firestore';

export default function MaterialWorker() {
  // In production setup, intercept these parameters from the system session cookies/props storage values
  const currentVendorStationId = "platform no 1"; 
  const currentActiveWorkerName = "Ramesh Kumar";

  const [transactionType, setTransactionType] = useState('WITHDRAW'); // DEPOSIT or WITHDRAW
  const [deltaQuantity, setDeltaQuantity] = useState('');
  const [photoPayload, setPhotoPayload] = useState(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const videoStreamRef = useRef(null);
  const captureCanvasRef = useRef(null);

  const toggleCameraStream = async () => {
    setPhotoPayload(null);
    setCameraActive(true);
    try {
      const liveMediaStream = await navigator.mediaDevices.getUserMedia({
        video: { facingMode: 'environment' },
        audio: false
      });
      if (videoStreamRef.current) videoStreamRef.current.srcObject = liveMediaStream;
    } catch (err) {
      alert("Hardware Block: Camera device context mapping failed.");
      setCameraActive(false);
    }
  };

  const processFrameSnapshot = () => {
    if (videoStreamRef.current && captureCanvasRef.current) {
      const renderContext = captureCanvasRef.current.getContext('2d');
      captureCanvasRef.current.width = videoStreamRef.current.videoWidth;
      captureCanvasRef.current.height = videoStreamRef.current.videoHeight;
      renderContext.drawImage(videoStreamRef.current, 0, 0, captureCanvasRef.current.width, captureCanvasRef.current.height);
      setPhotoPayload(captureCanvasRef.current.toDataURL('image/jpeg', 0.85));
      killCameraTracks();
    }
  };

  const killCameraTracks = () => {
    if (videoStreamRef.current && videoStreamRef.current.srcObject) {
      videoStreamRef.current.srcObject.getTracks().forEach(track => track.stop());
    }
    setCameraActive(false);
  };

  const dispatchLogTransaction = async (e) => {
    e.preventDefault();
    const parsedWeightValue = Number(deltaQuantity);

    if (!parsedWeightValue || parsedWeightValue <= 0) return alert("Specify valid numeric quantities.");
    if (!photoPayload) return alert("Audit Lock Triggered: Real-time image of materials state required.");

    setIsProcessing(true);

    try {
      const rootVendorRef = doc(db, "vendors", currentVendorStationId);
      const snapshotNode = await getDoc(rootVendorRef);

      if (!snapshotNode.exists()) {
        setIsProcessing(false);
        return alert("Parent registry code reference broken inside Firestore root.");
      }

      const initialInventoryMetric = Number(snapshotNode.data().totalStockCurrent || 0);

      if (transactionType === 'WITHDRAW' && initialInventoryMetric < parsedWeightValue) {
        setIsProcessing(false);
        return alert(`Insolvent Metrics: Attempting extraction of (${parsedWeightValue}) units from available (${initialInventoryMetric}) inventory.`);
      }

      const postComputeSum = transactionType === 'DEPOSIT' 
        ? initialInventoryMetric + parsedWeightValue 
        : initialInventoryMetric - parsedWeightValue;

      // 1. Write transactional proof receipt log trace array inside sub-collection path
      const transactionLoggerSubRef = collection(db, "vendors", currentVendorStationId, "transactions");
      await addDoc(transactionLoggerSubRef, {
        operator: currentActiveWorkerName,
        actionType: transactionType,
        deltaWeightShift: parsedWeightValue,
        openingStockBalance: initialInventoryMetric,
        closingStockBalance: postComputeSum,
        base64ProofFrame: photoPayload,
        timestamp: new Date()
      });

      // 2. Adjust central mathematical variable atomically on root parent documentation node 
      await updateDoc(rootVendorRef, {
        totalStockCurrent: increment(transactionType === 'DEPOSIT' ? parsedWeightValue : -parsedWeightValue)
      });

      alert(`Database States Mutated!\nDynamic Inventory Realized: ${postComputeSum} units on station node.`);
      setDeltaQuantity('');
      setPhotoPayload(null);

    } catch (err) {
      console.error(err);
      alert("Operational Synchronization Framework Exception.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div style={{ background: '#0F172A', minHeight: '100vh', display: 'flex', justifyContent: 'center', alignItems: 'center', padding: '20px', color: '#F8FAFC', fontFamily: 'system-ui' }}>
      <div style={{ background: '#1E293B', borderRadius: '16px', width: '100%', maxWidth: '400px', padding: '24px', border: '1px solid #334155' }}>
        
        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <h2 style={{ fontSize: '20px', fontWeight: 800, margin: '0 0 4px 0' }}>Material Storage Node Portal</h2>
          <p style={{ fontSize: '12px', color: '#94A3B8', margin: 0 }}>Active Profile Session: <strong>{currentActiveWorkerName}</strong></p>
        </div>

        <form onSubmit={dispatchLogTransaction} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div>
            <label style={{ display: 'block', fontSize: '10px', fontWeight: 700, color: '#94A3B8', marginBottom: '6px', letterSpacing: '0.5px' }}>LOGISTICS INVENTORY OPERATIONS STRATEGY</label>
            <div style={{ display: 'flex', background: '#0F172A', borderRadius: '8px', padding: '4px' }}>
              <button type="button" onClick={() => setTransactionType('WITHDRAW')} style={{ flex: 1, padding: '10px', background: transactionType === 'WITHDRAW' ? '#EF4444' : 'transparent', color: '#fff', border: 'none', borderRadius: '6px', fontWeight: 700, cursor: 'pointer' }}>🛑 WITHDRAW (Stock Out)</button>
              <button type="button" onClick={() => setTransactionType('DEPOSIT')} style={{ flex: 1, padding: '10px', background: transactionType === 'DEPOSIT' ? '#10B981' : 'transparent', color: '#fff', border: 'none', borderRadius: '6px', fontWeight: 700, cursor: 'pointer' }}>📥 DEPOSIT (Stock In)</button>
            </div>
          </div>

          <div>
            <label style={{ display: 'block', fontSize: '10px', fontWeight: 700, color: '#94A3B8', marginBottom: '6px' }}>MATERIAL QUANTITY / UNIT SHIFT WEIGHT</label>
            <input type="number" value={deltaQuantity} onChange={e => setDeltaQuantity(e.target.value)} placeholder="Provide material counts..." style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #334155', background: '#0F172A', color: '#fff', boxSizing: 'border-box' }} required />
          </div>

          <div>
            <label style={{ display: 'block', fontSize: '10px', fontWeight: 700, color: '#94A3B8', marginBottom: '6px' }}>STATE AUDIT PHOTO BLOCK VERIFICATION</label>
            <canvas ref={captureCanvasRef} style={{ display: 'none' }} />
            
            {cameraActive && (
              <div style={{ background: '#000', borderRadius: '10px', overflow: 'hidden', position: 'relative', display: 'flex', marginBottom: '10px' }}>
                <video ref={videoStreamRef} autoPlay playsInline style={{ width: '100%', height: '180px', objectFit: 'cover' }} />
                <button type="button" onClick={processFrameSnapshot} style={{ position: 'absolute', bottom: '12px', left: '50%', transform: 'translateX(-50%)', background: '#3B82F6', border: 'none', borderRadius: '50%', width: '44px', height: '44px', cursor: 'pointer' }}>📸</button>
              </div>
            )}

            {photoPayload && (
              <div style={{ marginBottom: '10px' }}>
                <img src={photoPayload} alt="Inventory snapshot" style={{ width: '100%', height: '160px', objectFit: 'cover', borderRadius: '10px', border: '2px solid #3B82F6' }} />
              </div>
            )}

            {!cameraActive && (
              <button type="button" onClick={toggleCameraStream} style={{ width: '100%', padding: '11px', background: '#475569', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 700, fontSize: '12px', cursor: 'pointer' }}>
                {photoPayload ? "🔄 Retake Payload Asset Frame" : "📷 Initialize Material Device Lens Capture"}
              </button>
            )}
          </div>

          <button type="submit" disabled={isProcessing} style={{ width: '100%', padding: '14px', background: isProcessing ? '#64748B' : transactionType === 'WITHDRAW' ? '#DC2626' : '#059669', color: '#fff', border: 'none', borderRadius: '8px', fontWeight: 800, fontSize: '13px', cursor: isProcessing ? 'not-allowed' : 'pointer', textTransform: 'uppercase', marginTop: '6px' }}>
            {isProcessing ? "Processing Matrix Audit Changes..." : `Confirm & Commit ${transactionType}`}
          </button>
        </form>
      </div>
    </div>
  );
}
